using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models
{
    [TestClass]
    public sealed class PersonTests
    {
        [TestMethod]
        public void FullName_ViaStudent_ReturnsLastNameCommaFirstName()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John"
            };

            Assert.AreEqual("Smith, John", student.FullName);
        }

        [TestMethod]
        public void FullName_ViaInstructor_ReturnsLastNameCommaFirstName()
        {
            var instructor = new Instructor
            {
                LastName = "Doe",
                FirstMidName = "Jane"
            };

            Assert.AreEqual("Doe, Jane", instructor.FullName);
        }

        [TestMethod]
        [DataRow("O'Brien", "Mary", "O'Brien, Mary", DisplayName = "Name with apostrophe")]
        [DataRow("Van Der Berg", "Jan", "Van Der Berg, Jan", DisplayName = "Multi-word last name")]
        [DataRow("A", "B", "A, B", DisplayName = "Single character names")]
        public void FullName_VariousNames_FormatsCorrectly(string lastName, string firstName, string expected)
        {
            var student = new Student
            {
                LastName = lastName,
                FirstMidName = firstName
            };

            Assert.AreEqual(expected, student.FullName);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models
{
    [TestClass]
    public sealed class ErrorViewModelTests
    {
        [TestMethod]
        public void ShowRequestId_WithValue_ReturnsTrue()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };
            Assert.IsTrue(model.ShowRequestId);
        }

        [TestMethod]
        public void ShowRequestId_WithNull_ReturnsFalse()
        {
            var model = new ErrorViewModel { RequestId = null };
            Assert.IsFalse(model.ShowRequestId);
        }

        [TestMethod]
        public void ShowRequestId_WithEmptyString_ReturnsFalse()
        {
            var model = new ErrorViewModel { RequestId = "" };
            Assert.IsFalse(model.ShowRequestId);
        }

        [TestMethod]
        public void RequestId_SetAndGet_RoundTrips()
        {
            var model = new ErrorViewModel { RequestId = "test-id-42" };
            Assert.AreEqual("test-id-42", model.RequestId);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_WithValidInputs_SetsPageIndex()
        {
            var items = new List<int> { 1, 2, 3 };

            var list = new PaginatedList<int>(items, 30, 2, 10);

            Assert.AreEqual(2, list.PageIndex);
        }

        [TestMethod]
        public void Constructor_WithValidInputs_SetsTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };

            var list = new PaginatedList<int>(items, 30, 2, 10);

            Assert.AreEqual(3, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_WithItems_AddsAllItemsToList()
        {
            var items = new List<int> { 1, 2, 3, 4, 5 };

            var list = new PaginatedList<int>(items, 20, 1, 5);

            Assert.AreEqual(5, list.Count);
            CollectionAssert.AreEqual(items, list);
        }

        [TestMethod]
        [DataRow(25, 10, 3, DisplayName = "25 items / 10 per page = 3 pages")]
        [DataRow(30, 10, 3, DisplayName = "30 items / 10 per page = 3 pages (exact)")]
        [DataRow(1, 10, 1, DisplayName = "1 item / 10 per page = 1 page")]
        [DataRow(10, 3, 4, DisplayName = "10 items / 3 per page = 4 pages")]
        [DataRow(0, 10, 0, DisplayName = "0 items = 0 pages")]
        [DataRow(100, 25, 4, DisplayName = "100 items / 25 per page = 4 pages")]
        public void TotalPages_VariousCounts_CalculatesCorrectly(int count, int pageSize, int expectedTotalPages)
        {
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            Assert.AreEqual(expectedTotalPages, list.TotalPages);
        }

        [TestMethod]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);

            Assert.IsFalse(list.HasPreviousPage);
