using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateContext();
            _controller = new StudentsController(_context);
            TestHelper.SetupController(_controller);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        #region Index Tests

        [TestMethod]
        public void Index_NoParams_ReturnsViewWithAllStudents()
        {
            // Arrange
            _context.Students.AddRange(
                new Student { FirstMidName = "John", LastName = "Doe", EnrollmentDate = DateTime.Parse("2020-01-01") },
                new Student { FirstMidName = "Jane", LastName = "Smith", EnrollmentDate = DateTime.Parse("2020-01-01") }
            );
            _context.SaveChanges();

            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);
        }

        [TestMethod]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            // Arrange
            _context.Students.AddRange(
                new Student { FirstMidName = "John", LastName = "Zeta", EnrollmentDate = DateTime.Parse("2020-01-01") },
                new Student { FirstMidName = "Jane", LastName = "Alpha", EnrollmentDate = DateTime.Parse("2020-01-01") }
            );
            _context.SaveChanges();

            // Act
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual("Alpha", model[0].LastName);
            Assert.AreEqual("Zeta", model[1].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            // Arrange
            _context.Students.AddRange(
                new Student { FirstMidName = "John", LastName = "Alpha", EnrollmentDate = DateTime.Parse("2020-01-01") },
                new Student { FirstMidName = "Jane", LastName = "Zeta", EnrollmentDate = DateTime.Parse("2020-01-01") }
            );
            _context.SaveChanges();

            // Act
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual("Zeta", model[0].LastName);
            Assert.AreEqual("Alpha", model[1].LastName);
        }

        [TestMethod]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            // Arrange
            _context.Students.AddRange(
                new Student { FirstMidName = "A", LastName = "Late", EnrollmentDate = DateTime.Parse("2022-01-01") },
                new Student { FirstMidName = "B", LastName = "Early", EnrollmentDate = DateTime.Parse("2020-01-01") }
            );
            _context.SaveChanges();

            // Act
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            // Assert
            Assert.AreEqual("Early", model[0].LastName);
            Assert.AreEqual("Late", model[1].LastName);
        }

        [TestMethod]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            // Arrange
            _context.Students.AddRange(
                new Student { FirstMidName = "A", LastName = "Early", EnrollmentDate = DateTime.Parse("2020-01-01") },
                new Student { FirstMidName = "B", LastName = "Late", EnrollmentDate = DateTime.Parse("2022-01-01") }
            );
            _context.SaveChanges();

