            _context.Students.AddRange(
                new Student { FirstMidName = "John", LastName = "Doe", EnrollmentDate = DateTime.Parse("2020-01-01") },
                new Student { FirstMidName = "Jane", LastName = "Smith", EnrollmentDate = DateTime.Parse("2020-01-01") }
            );
