        #region Details Tests

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            // Arrange
            var student = new Student { FirstMidName = "John", LastName = "Doe", EnrollmentDate = DateTime.Parse("2020-01-01") };
            _context.Students.Add(student);
            _context.SaveChanges();

            // Act
            var result = _controller.Details(student.ID) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual("Doe", model.LastName);
            Assert.AreEqual("John", model.FirstMidName);
        }

        #endregion

        #region Create Tests

        [TestMethod]
        public void Create_Get_ReturnsViewWithStudent()
        {
            var result = _controller.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        [TestMethod]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            // Act
            var result = _controller.Create(student) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(1, _context.Students.Count());
        }

        [TestMethod]
        public void Create_Post_ValidStudent_SavesStudentToDatabase()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "John",
                LastName = "NewStudent",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            // Act
            _controller.Create(student);

            // Assert
            var savedStudent = _context.Students.Single();
            Assert.AreEqual("John", savedStudent.FirstMidName);
            Assert.AreEqual("NewStudent", savedStudent.LastName);
        }

        [TestMethod]
        public void Create_Post_MinValueDate_ReturnsViewWithModelError()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            // Act
            var result = _controller.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
