        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateContext();
            _controller = new NotificationsController(_context);
            TestHelper.SetupController(_controller);

            // Drain any existing notifications from static queue
            _drainService = new NotificationService();
            while (_drainService.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _drainService?.Dispose();
            _controller?.Dispose();
            _context?.Dispose();
        }

        #region GetNotifications Tests

        [TestMethod]
        public void GetNotifications_NoNotifications_ReturnsSuccessWithEmptyList()
        {
            // Act
