            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);

            // Verify the JSON contains success=true and count=0
            var json = result.Value;
            var successProp = json.GetType().GetProperty("success");
            var countProp = json.GetType().GetProperty("count");
            Assert.AreEqual(true, successProp.GetValue(json));
            Assert.AreEqual(0, countProp.GetValue(json));
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotificationsInResult()
        {
            // Arrange - send notifications through a service
            var service = new NotificationService();
