using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Data
{
    [TestClass]
    public sealed class DbInitializerTests
    {
        private SchoolContext _context;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateContext();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _context?.Dispose();
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsStudents()
        {
            DbInitializer.Initialize(_context);

            Assert.AreEqual(8, _context.Students.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsInstructors()
        {
            DbInitializer.Initialize(_context);

            Assert.AreEqual(5, _context.Instructors.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsDepartments()
        {
            DbInitializer.Initialize(_context);

            Assert.AreEqual(4, _context.Departments.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsCourses()
        {
            DbInitializer.Initialize(_context);

            Assert.AreEqual(7, _context.Courses.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsEnrollments()
        {
            DbInitializer.Initialize(_context);

            Assert.AreEqual(11, _context.Enrollments.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
        {
            DbInitializer.Initialize(_context);

            Assert.AreEqual(3, _context.OfficeAssignments.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsCourseAssignments()
        {
            DbInitializer.Initialize(_context);

            Assert.AreEqual(8, _context.CourseAssignments.Count());
        }

        [TestMethod]
        public void Initialize_ExistingStudents_DoesNotReseed()
        {
            // Arrange - add one student so the database is not empty
            _context.Students.Add(new Student
            {
                FirstMidName = "Existing",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            });
            _context.SaveChanges();

            // Act
            DbInitializer.Initialize(_context);

            // Assert - should still have only 1 student (no seeding occurred)
            Assert.AreEqual(1, _context.Students.Count());
        }

        [TestMethod]
        public void Initialize_ExistingStudents_DoesNotAddInstructors()
        {
            // Arrange
            _context.Students.Add(new Student
            {
                FirstMidName = "Existing",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            });
            _context.SaveChanges();

            // Act
            DbInitializer.Initialize(_context);

            // Assert - no instructors should be seeded
            Assert.AreEqual(0, _context.Instructors.Count());
        }

        [TestMethod]
        public void Initialize_SeedsSpecificStudentNames()
        {
            DbInitializer.Initialize(_context);

            var studentNames = _context.Students.Select(s => s.LastName).OrderBy(n => n).ToList();
            CollectionAssert.Contains(studentNames, "Alexander");
            CollectionAssert.Contains(studentNames, "Alonso");
            CollectionAssert.Contains(studentNames, "Anand");
            CollectionAssert.Contains(studentNames, "Barzdukas");
        }

        [TestMethod]
        public void Initialize_SeedsSpecificDepartmentNames()
        {
            DbInitializer.Initialize(_context);

            var deptNames = _context.Departments.Select(d => d.Name).OrderBy(n => n).ToList();
            CollectionAssert.Contains(deptNames, "English");
            CollectionAssert.Contains(deptNames, "Mathematics");
            CollectionAssert.Contains(deptNames, "Engineering");
            CollectionAssert.Contains(deptNames, "Economics");
        }

        [TestMethod]
        public void Initialize_SeedsCoursesWithCorrectCredits()
        {
            DbInitializer.Initialize(_context);

            var chemistry = _context.Courses.Single(c => c.Title == "Chemistry");
            Assert.AreEqual(3, chemistry.Credits);

            var calculus = _context.Courses.Single(c => c.Title == "Calculus");
            Assert.AreEqual(4, calculus.Credits);
        }

        [TestMethod]
        public void Initialize_SeedsEnrollmentsWithGrades()
        {
            DbInitializer.Initialize(_context);

            // Carson Alexander's Chemistry enrollment should have Grade A
            var alexander = _context.Students.Single(s => s.LastName == "Alexander");
            var chemistry = _context.Courses.Single(c => c.Title == "Chemistry");
            var enrollment = _context.Enrollments
                .Single(e => e.StudentID == alexander.ID && e.CourseID == chemistry.CourseID);

            Assert.AreEqual(Grade.A, enrollment.Grade);
        }

        [TestMethod]
        public void Initialize_SeedsEnrollmentsWithNullGrade()
        {
            DbInitializer.Initialize(_context);

            // Arturo Anand's Chemistry enrollment should have no grade
            var anand = _context.Students.Single(s => s.LastName == "Anand");
            var chemistry = _context.Courses.Single(c => c.Title == "Chemistry");
            var enrollment = _context.Enrollments
                .Single(e => e.StudentID == anand.ID && e.CourseID == chemistry.CourseID);

            Assert.IsNull(enrollment.Grade);
        }

        [TestMethod]
        public void Initialize_CalledTwice_DoesNotDuplicateData()
        {
            // Act
            DbInitializer.Initialize(_context);
            DbInitializer.Initialize(_context);

            // Assert - same counts as single call
            Assert.AreEqual(8, _context.Students.Count());
            Assert.AreEqual(5, _context.Instructors.Count());
        }
    }
}

