    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context;
        private NotificationsController _controller;
        private NotificationService _drainService;

        [TestInitialize]
        public void Setup()
        {
            _context = TestHelper.CreateContext();
            _controller = new NotificationsController(_context);
            TestHelper.SetupController(_controller);

            // Drain any existing notifications from static queue
            _drainService = new NotificationService();
            while (_drainService.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _drainService?.Dispose();
            _controller?.Dispose();
            _context?.Dispose();
        }

        #region GetNotifications Tests

        [TestMethod]
        public void GetNotifications_NoNotifications_ReturnsSuccessWithEmptyList()
        {
            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);

            // Verify the JSON contains success=true and count=0
            var json = result.Value;
            var successProp = json.GetType().GetProperty("success");
            var countProp = json.GetType().GetProperty("count");
            Assert.AreEqual(true, successProp.GetValue(json));
            Assert.AreEqual(0, countProp.GetValue(json));
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotificationsInResult()
        {
            // Arrange - send notifications through a service
            var service = new NotificationService();
            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");
            service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "admin");

            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var json = result.Value;
            var successProp = json.GetType().GetProperty("success");
            var countProp = json.GetType().GetProperty("count");
            Assert.AreEqual(true, successProp.GetValue(json));
            Assert.AreEqual(2, countProp.GetValue(json));

            service.Dispose();
        }

        [TestMethod]
        public void GetNotifications_ReturnsJsonResult()
        {
            var result = _controller.GetNotifications();

            Assert.IsInstanceOfType(result, typeof(JsonResult));
        }

        #endregion

        #region MarkAsRead Tests

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            // Act
            var result = _controller.MarkAsRead(1);

            // Assert
            Assert.IsNotNull(result);
            var json = result.Value;
            var successProp = json.GetType().GetProperty("success");
            Assert.AreEqual(true, successProp.GetValue(json));
        }

        [TestMethod]
        public void MarkAsRead_ReturnsJsonResult()
        {
            var result = _controller.MarkAsRead(42);

            Assert.IsInstanceOfType(result, typeof(JsonResult));
        }

        #endregion

        #region Index Tests

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        #endregion
    }
