+            CollectionAssert.Contains(studentNames, "Barzdukas");
+        }
+
+        [TestMethod]
+        public void Initialize_SeedsSpecificDepartmentNames()
+        {
+            DbInitializer.Initialize(_context);
+
+            var deptNames = _context.Departments.Select(d => d.Name).OrderBy(n => n).ToList();
+            CollectionAssert.Contains(deptNames, "English");
+            CollectionAssert.Contains(deptNames, "Mathematics");
+            CollectionAssert.Contains(deptNames, "Engineering");
+            CollectionAssert.Contains(deptNames, "Economics");
+        }
+
+        [TestMethod]
+        public void Initialize_SeedsCoursesWithCorrectCredits()
+        {
+            DbInitializer.Initialize(_context);
+
+            var chemistry = _context.Courses.Single(c => c.Title == "Chemistry");
+            Assert.AreEqual(3, chemistry.Credits);
+
+            var calculus = _context.Courses.Single(c => c.Title == "Calculus");
+            Assert.AreEqual(4, calculus.Credits);
+        }
+
+        [TestMethod]
+        public void Initialize_SeedsEnrollmentsWithGrades()
+        {
+            DbInitializer.Initialize(_context);
+
+            // Carson Alexander's Chemistry enrollment should have Grade A
+            var alexander = _context.Students.Single(s => s.LastName == "Alexander");
+            var chemistry = _context.Courses.Single(c => c.Title == "Chemistry");
+            var enrollment = _context.Enrollments
+                .Single(e => e.StudentID == alexander.ID && e.CourseID == chemistry.CourseID);
+
+            Assert.AreEqual(Grade.A, enrollment.Grade);
+        }
+
+        [TestMethod]
+        public void Initialize_SeedsEnrollmentsWithNullGrade()
+        {
+            DbInitializer.Initialize(_context);
+
+            // Arturo Anand's Chemistry enrollment should have no grade
+            var anand = _context.Students.Single(s => s.LastName == "Anand");
+            var chemistry = _context.Courses.Single(c => c.Title == "Chemistry");
+            var enrollment = _context.Enrollments
+                .Single(e => e.StudentID == anand.ID && e.CourseID == chemistry.CourseID);
+
+            Assert.IsNull(enrollment.Grade);
+        }
+
+        [TestMethod]
+        public void Initialize_CalledTwice_DoesNotDuplicateData()
+        {
+            // Act
+            DbInitializer.Initialize(_context);
+            DbInitializer.Initialize(_context);
+
+            // Assert - same counts as single call
+            Assert.AreEqual(8, _context.Students.Count());
+            Assert.AreEqual(5, _context.Instructors.Count());
+        }
+    }
+}
