        public void Create_ReturnsSchoolContextInstance()
        {
            // Arrange
            var inMemorySettings = new Dictionary<string, string>
            {
                { "ConnectionStrings:DefaultConnection", "Server=test;Database=TestDb;" }
            };

            var configuration = new ConfigurationBuilder()
                .AddInMemoryCollection(inMemorySettings)
                .Build();

            // Act
            var context = SchoolContextFactory.Create(configuration);

            // Assert
            Assert.IsInstanceOfType(context, typeof(SchoolContext));
            context.Dispose();
        }
    }
}

